mapper.select:
SELECT c.COMMENT_ID AS commentId, c.PRODUCT_ID AS productId, c.MEMBER_ID AS memberId, m.NICKNAME AS nickname, p.PRODUCT_NAME AS productName, c.CONTENT AS content, c.STATUS AS status, TO_CHAR(c.CREATED_AT, 'YYYY-MM-DD HH24:MI') AS createdAt, TO_CHAR(c.UPDATED_AT, 'YYYY-MM-DD HH24:MI') AS updatedAt, TO_CHAR(c.DELETED_AT, 'YYYY-MM-DD HH24:MI') AS deletedAt, c.DELETED_BY AS deletedBy, c.DELETE_REASON AS deleteReason FROM BL_PRODUCT_COMMENTS c JOIN BL_MEMBERS m ON c.MEMBER_ID = m.MEMBER_ID JOIN BL_PRODUCTS p ON c.PRODUCT_ID = p.PRODUCT_ID
AND c.STATUS = #{status}
ORDER BY c.COMMENT_ID DESC FETCH FIRST #{size} ROWS ONLY

mapper.update:
UPDATE BL_PRODUCT_COMMENTS
   SET CONTENT    = #{content,jdbcType=VARCHAR},
       UPDATED_AT = SYSDATE
 WHERE COMMENT_ID = #{commentId,jdbcType=NUMERIC}
   AND MEMBER_ID  = #{memberId,jdbcType=NUMERIC}
   AND STATUS     = 'ACTIVE'

UPDATE BL_PRODUCT_COMMENTS
   SET STATUS        = 'DELETED',
       DELETED_AT    = SYSDATE,
       DELETED_BY    = #{adminId},
       DELETE_REASON = #{reason}
 WHERE COMMENT_ID = #{commentId}
